-- ═══════════════════════════════════════════════════════════════════════════════
-- ffta.lua — game module for the Archipelago BizHawk connector.
--            Final Fantasy Tactics Advance (GBA)
--
-- STATUS: location DETECTION + goal are REAL and SOURCE-DERIVED from the AP world
-- worlds/ffta (spicynun/Archipelago, branch `ffta`, commit 08c19b3 — a fork of
-- ArchipelagoMW/Archipelago). The 311-group / 1866-location table below was
-- GENERATED by EXECUTING worlds/ffta/locations.py (its own MissionGroups +
-- DispatchMissionGroups builder loop) — not hand-copied — so the (byte,mask)->ids
-- mapping is exact. The flag-scan, goal byte and ROM-name guard replicate
-- FFTAClient.game_watcher byte-for-byte. Loads crash-free on any ROM and
-- self-disables on a non-FFTA / non-US cartridge.
--
-- SOURCE: https://github.com/spicynun/Archipelago/blob/ffta/worlds/ffta/client.py
--         https://github.com/spicynun/Archipelago/blob/ffta/worlds/ffta/locations.py
--
-- MEMORY MODEL (BizHawk GBA — the exact domains FFTAClient reads)
-- ──────────────────────────────────────────────────────────────
--   "System Bus" : the client reads everything off the GBA System Bus. The
--                  50-byte mission-complete flag array lives at 0x2001FD0
--                  (this is EWRAM 0x1FD0 mirrored on the bus), the 1-byte goal
--                  flag at 0x2002192.
--   "ROM"        : cartridge identity name at 0x0A0 (10 bytes "FFTA_USVER").
--
-- DETECTION (mirrors FFTAClient.game_watcher, client.py line ~158)
--   The client reads 50 bytes at 0x2001FD0, then:
--     for byte_i, byte in enumerate(flag_bytes):
--       for i in 0..7:
--         if byte & (1<<i) == bitflags[i]:            -- bit i is set
--           for mission in MissionGroups + DispatchMissionGroups:
--             if byte & (1<<i) == mission.mask and byte_i == mission.byte_index:
--               for loc in mission.locations: add loc.rom_address  (∈ server_locations)
--   Each mission group is (locations[6], mask, byte_index); the location's
--   rom_address IS the AP location id (locations.py
--   create_location_label_to_id_map). Every (byte_index, mask) pair is UNIQUE
--   across the 311 groups (verified at generation), so GROUPS[byte][mask] = the
--   six ids that fire when flag_bytes[byte] has bit `mask` set. We emit all six,
--   gated to the slot's server location set so unrelated games' ids never leak.
--
-- GOAL (game_watcher line ~154): the 1-byte flag at 0x2002192 == goal_id, where
--   goal_id is chosen from slot_data["final_mission"]:
--     0 (Royal Valley)  → 0x64      1 (Decision Time) → 0x93
--   The goal is only ever reported once goal_id is known (slot_data present) and
--   non-zero — exactly the client's `goal_flag == goal_id and goal_id != 0`.
--
-- ITEM DELIVERY (items_handling = 0b101: remote items + starting inventory)
-- ──────────────────────────────────────────────────────────────────────────
--   receive_item is a documented NO-OP. FFTA is NOT a self-granting ROM for
--   remote items, but its delivery path is intricate and state-sensitive: the
--   client (client.py line ~197) writes the next item id AND a one-item
--   lookahead into a System-Bus mailbox (0x201f46c/0x201f46e), bumps the game's
--   own received-item counter at 0x2002AF0, sets a trigger byte at 0x200f85c,
--   and does it all through a guarded_write gated on a multi-byte guard list
--   (0x200f85c/0x2019EB9/0x2019976/0x201997F) PLUS a "Marche is not moving on
--   the world map" check (0x200FA18 != 0). Mis-timing any of that corrupts the
--   in-game item queue. That handshake needs in-emulator confirmation before it
--   is wired, so it is intentionally deferred rather than shipped unverified —
--   the same posture as the other 0b1x1 GBA modules. Detection + goal are fully
--   live; a solo seed still reports every check and completes its goal.
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "ffta"

local ADDRESSES_VERIFIED = true   -- tables generated from worlds/ffta source

-- ── Memory domains ────────────────────────────────────────────────────────────
local SYSBUS = "System Bus"
local ROM    = "ROM"

-- ── Addresses / constants (worlds/ffta/client.py) ─────────────────────────────
local FLAGS_ARRAY_START = 0x2001FD0   -- System Bus: 50-byte mission-complete flags
local FLAGS_ARRAY_LEN   = 50
local GOAL_FLAG_ADDR    = 0x2002192   -- System Bus: 1-byte goal flag (== goal_id)
local ROM_NAME_ADDR     = 0x0A0       -- ROM: cartridge identity (10 bytes)
local ROM_NAME          = "FFTA_USVER"

-- final_mission (slot_data) → goal_id (game_watcher line ~89)
local GOAL_ID_ROYAL_VALLEY = 0x64     -- final_mission == 0
local GOAL_ID_DECISION_TIME = 0x93    -- final_mission == 1

