-- ── State ─────────────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil     -- cached ROM-name result
local goal_id          = 0       -- resolved from slot_data.final_mission (0 = unknown)
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[ffta] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8 = memory.read_u8 or memory.readbyte
  return mem.read_u8 ~= nil
end

local function read_u8(addr, domain)
  if not mem.read_u8 then return nil end
  local ok, v = pcall(mem.read_u8, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, addr)            -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

-- ── Bit helper (pure Lua, no bit library dependency) ──────────────────────────
local function bit_and(a, b)
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

local MASKS = { 0x01, 0x02, 0x04, 0x08, 0x10, 0x20, 0x40, 0x80 }

-- ── ROM identity: validate_rom checks the 10-byte name "FFTA_USVER" @0x0A0 ─────
local function read_string(addr, len, domain)
  local out = {}
  for i = 0, len - 1 do
    local b = read_u8(addr + i, domain)
    if b == nil then return nil end           -- not readable yet; retry next poll
    out[#out + 1] = string.char(b)
  end
  return table.concat(out)
end

local function rom_is_ffta()
  if rom_ok ~= nil then return rom_ok end
  local name = read_string(ROM_NAME_ADDR, #ROM_NAME, ROM)
  if name == nil then return false end          -- not readable yet; retry next poll
  if name ~= ROM_NAME then
    rom_ok = false
    log("non-FFTA/US ROM (name '" .. tostring(name) .. "' != FFTA_USVER) — detection idle")
    return false
  end
  rom_ok = true
  log("FFTA US ROM verified (name 'FFTA_USVER')")
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end
  return server_locations[ap_id] == true
end

-- final_mission (slot_data) → goal_id (game_watcher line ~89)
local function resolve_goal(cfg)
  local sd = cfg and cfg.slot_data
  if type(sd) ~= "table" then return end
  local fm = sd.final_mission
  if fm == nil then return end
  fm = tonumber(fm)
  if fm == 0 then
    goal_id = GOAL_ID_ROYAL_VALLEY
    log("goal: Royal Valley (final_mission=0, goal_id=0x64)")
  elseif fm == 1 then
    goal_id = GOAL_ID_DECISION_TIME
    log("goal: Decision Time (final_mission=1, goal_id=0x93)")
  end
end

-- ── Flag array (read once per poll) ───────────────────────────────────────────
local flags = {}     -- byte index -> value, refreshed each poll

local function refresh_flags()
  for i = 0, FLAGS_ARRAY_LEN - 1 do
    flags[i] = read_u8(FLAGS_ARRAY_START + i, SYSBUS)
  end
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  resolve_goal(cfg)
  local groups, locs = 0, 0
  for _, byte_groups in pairs(GROUPS) do
    for _, ids in pairs(byte_groups) do groups = groups + 1; locs = locs + #ids end
  end
  log(string.format("ready: %d location groups, %d locations", groups, locs))
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ffta() then return new end
  refresh_flags()

  -- Mirror game_watcher: for each flag byte that has a group table, fire every
  -- group whose mask bit is set in that byte, emitting all six location ids
  -- (gated to the server's location set). (byte,mask) keys are unique, so a set
  -- bit maps to exactly one group's id list.
  for byte_i, byte_groups in pairs(GROUPS) do
    local byte = flags[byte_i]
    if byte and byte ~= 0 then
      for _, mask in ipairs(MASKS) do
        if bit_and(byte, mask) ~= 0 then
          local ids = byte_groups[mask]
          if ids then
            for k = 1, #ids do
              local ap_id = ids[k]
              if not reported[ap_id] and wanted(ap_id) then
                reported[ap_id] = true
                new[#new + 1] = ap_id
              end
            end
          end
        end
      end
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ffta() then return false end
  -- game_watcher: game_clear when goal_flag == goal_id AND goal_id != 0.
  if goal_id == 0 then return false end
  local g = read_u8(GOAL_FLAG_ADDR, SYSBUS)
  return g ~= nil and g == goal_id
end

-- Remote multiworld items: see the file header. items_handling = 0b101, but the
-- FFTA delivery path is a guarded System-Bus mailbox handshake with a one-item
-- lookahead, a world-map "not moving" gate and the game's own received-item
-- counter — intricate enough to require in-emulator confirmation before wiring.
-- Deferred (never a wrong write) until then. No-op (documented).
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
